/* 57,EDQT-57 */ select distinct CONCAT(cons_attribute,',',invoice_nbr,',',product_id,',',account_number) as Primary_Key,time_zone,'57' as MAPPING_ID from adh_genpro_use2_prd.g_product360.ontime_delivery_hhd tablesample(10 percent) WHERE (cons_attribute IS NOT NULL OR invoice_nbr IS NOT NULL OR product_id IS NOT NULL OR account_number IS NOT NULL) /* BEGIN_SECONDARY_SQL */ AND CAST(time_zone as Decimal)<0.0;
/* 57,EDQT-57 */ select distinct CONCAT(cons_attribute,',',invoice_nbr,',',product_id,',',account_number) as Primary_Key,time_zone,'57' as MAPPING_ID from adh_genpro_use2_prd.g_product360.ontime_delivery_hhd tablesample(10 percent) WHERE (cons_attribute IS NOT NULL OR invoice_nbr IS NOT NULL OR product_id IS NOT NULL OR account_number IS NOT NULL) /* BEGIN_SECONDARY_SQL */ AND CAST(time_zone as Decimal)<0.0;
/* 55,EDQT-55 */ SELECT distinct CONCAT(cons_attribute,',',invoice_nbr,',',product_id,',',account_number) as Primary_Key, cast(Ltrim(Rtrim(manifest_ear_dttm_local)) as date) AS manifest_ear_dttm_local,'55' as MAPPING_ID FROM adh_genpro_use2_prd.g_product360.ontime_delivery_hhd tablesample(10 percent) WHERE (cons_attribute IS NOT NULL OR invoice_nbr IS NOT NULL OR product_id IS NOT NULL OR account_number IS NOT NULL) /* BEGIN_SECONDARY_SQL */ AND DATEDIFF(month,manifest_ear_dttm_local,CAST(Getdate() AS DATE))>12;
